export function getSystemPrompt(influencer) {
  if (!influencer || !influencer.name) {
    throw new Error('Perfil de influencer obrigatГіrio. Cadastre uma influencer antes de continuar.');
  }
  // v3.3: passar facePrompt tambГ©m (antes era sГі name + bodyDescription)
  return buildCustomIdentity(
    influencer.name,
    influencer.bodyDescription || '',
    influencer.facePrompt || ''
  ) + "\n\n" + FULL_V82_PROMPT;
}

